module shift_reg8bit
(
  input  [7:0] data_in,
  input  clk,
  input  load,
  output serial_out
);

reg [7:0] shift_reg;

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
  if (load)
    shift_reg <= data_in;
  else
    shift_reg <= {1'b0, shift_reg[7:1]};
end

assign serial_out = shift_reg[0];

endmodule
